module calendar(
    input CLK,
    input RST,
    output reg [5:0] Hours,
    output reg [5:0] Mins,
    output reg [5:0] Secs
);

always @(posedge CLK or negedge RST) begin
    if (!RST) begin
        Secs <= 0;
        Mins <= 0;
        Hours <= 0;
    end
    else begin
        if (Secs == 59) begin
            Secs <= 0;
            if (Mins == 59) begin
                Mins <= 0;
                if (Hours == 23) begin
                    Hours <= 0;
                end
                else begin
                    Hours <= Hours + 1;
                end
            end
            else begin
                Mins <= Mins + 1;
            end
        end
        else begin
            Secs <= Secs + 1;
        end
    end
end

endmodule
